export const allClusterIds = ['kemenkeu', 'klpd'] as const;

export function getClusterLabel(id: ClusterId | string): string {
  if (id === "klpd") return klpdCluster.label;
  return "Kemenkeu";
}

export function getClusterChecklist(clusterId: ClusterId | string, subclusterId?: string): ChecklistItem[] {
  if (clusterId === "klpd") return klpdChecklist;
  if (subclusterId && kemenkeuChecklists[subclusterId]) return kemenkeuChecklists[subclusterId];
  return [];
}